using rocksdb::Slice;

bool SearchFilter::Filter([[maybe_unused]] int level, const Slice &key, [[maybe_unused]] const Slice &value,
                          [[maybe_unused]] std::string *new_value, [[maybe_unused]] bool *modified) const {
  // Search column family contains index metadata, field metadata, and vector index data
  // We need to filter out data that belongs to deleted indexes or fields

  // Extract namespace from the key
  std::string key_str = key.ToString();
  Slice key_slice(key_str);

  // The key structure for search data:
  // <namespace_size><namespace><subkey_type><index_name>...

  // First byte is namespace size
  if (key_slice.size() < 1) {
    return false; // keep invalid keys
  }

  uint8_t ns_size = static_cast<uint8_t>(key_slice[0]);
  key_slice.remove_prefix(1);

  if (key_slice.size() < ns_size) {
    return false; // keep invalid keys
  }

  std::string ns(key_slice.data(), ns_size);
  key_slice.remove_prefix(ns_size);

  // Next byte is subkey type
  if (key_slice.size() < 1) {
    return false; // keep invalid keys
  }

  uint8_t subkey_type = static_cast<uint8_t>(key_slice[0]);
  key_slice.remove_prefix(1);

  // For INDEX_META type, we need to check if the index still exists
  if (subkey_type == static_cast<uint8_t>(redis::SearchSubkeyType::INDEX_META)) {
    // The remaining key contains index name
    Slice index_name_slice = key_slice;

    // Check if the corresponding metadata key exists in metadata column family
    std::string metadata_key = ComposeNamespaceKey(ns, index_name_slice.ToString(), stor_->IsSlotIdEncoded());

    auto db = stor_->GetDB();
    const auto cf_handles = stor_->GetCFHandles();
    if (!db || cf_handles->size() < 2) return false; // keep if storage is closed

    std::string metadata_value;
    rocksdb::Status s = db->Get(rocksdb::ReadOptions(), (*cf_handles)[1], metadata_key, &metadata_value);

    // If metadata key doesn't exist, filter out this search entry
    if (s.IsNotFound()) {
      debug("[compact_filter/search] Filtering out deleted index: namespace: {}, index: {}", ns, index_name_slice.ToString());
      return true;
    }
  }

  // TODO: Add similar logic for FIELD_META and other subkey types
  // For now, keep all other search entries

  return false;
}

}  // namespace engine

